<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('communications.view');$pdo=obtenerConexion();$reportes=$pdo->query("SELECT r.*,m.contenido,m.remitente_id,CONCAT(u.nombre,' ',u.apellido) remitente,CONCAT(rr.nombre,' ',rr.apellido) reportante FROM chat_reportes r JOIN chat_mensajes m ON m.id=r.mensaje_id JOIN usuarios u ON u.id=m.remitente_id JOIN usuarios rr ON rr.id=r.reportado_por ORDER BY FIELD(r.estado,'pendiente','revisado','moderado','descartado'),r.created_at DESC LIMIT 200")->fetchAll();$bloqueos=$pdo->query("SELECT b.*,CONCAT(u.nombre,' ',u.apellido) usuario,CONCAT(a.nombre,' ',a.apellido) admin FROM chat_bloqueos b JOIN usuarios u ON u.id=b.usuario_id JOIN usuarios a ON a.id=b.bloqueado_por WHERE b.desbloqueado_at IS NULL ORDER BY b.bloqueado_at DESC")->fetchAll();cmsCabecera('Moderación de chat','comunicaciones/moderacion.php','Mensajes reportados y usuarios bloqueados.');?>
<div class="card card-rounded mb-4"><div class="card-body"><h2 class="h5">Reportes</h2><div class="table-responsive"><table class="table"><thead><tr><th>Mensaje</th><th>Remitente</th><th>Reportado por</th><th>Estado</th><th>Acciones</th></tr></thead><tbody><?php foreach($reportes as$r):?><tr><td><?=atenea_e(mb_strimwidth($r['contenido'],0,180,'…'))?></td><td><?=atenea_e($r['remitente'])?></td><td><?=atenea_e($r['reportante'])?></td><td><?=atenea_e($r['estado'])?></td><td><form method="post" action="moderacion-accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="reporte_id" value="<?=$r['id']?>"><button name="accion" value="moderar" class="btn btn-sm btn-danger">Moderar</button> <button name="accion" value="descartar" class="btn btn-sm btn-outline-secondary">Descartar</button> <button name="accion" value="bloquear" class="btn btn-sm btn-warning">Bloquear usuario</button></form></td></tr><?php endforeach;?></tbody></table></div></div></div><div class="card card-rounded"><div class="card-body"><h2 class="h5">Usuarios bloqueados</h2><?php foreach($bloqueos as$b):?><form class="border p-2 mb-2" method="post" action="moderacion-accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="usuario_id" value="<?=$b['usuario_id']?>"><strong><?=atenea_e($b['usuario'])?></strong> · <?=atenea_e($b['motivo'])?><button name="accion" value="desbloquear" class="btn btn-sm btn-outline-success float-end">Desbloquear</button></form><?php endforeach;?></div></div><?php cmsPie();
